const msg = $json.message;
if (!msg || !msg.text) return [];
return [{
  json: {
    chat_id: String(msg.chat.id),
    user_message: msg.text,
    user_name: msg.from?.first_name || 'Andrés'
  }
}];

// Primer input: tareas (HTTP — Tareas Supabase)
// Segundo input: proyecto (HTTP — Proyecto Supabase)
const allItems = $input.all();

// Separar por origen: items con 'descripcion' son tareas, con 'nombre' son proyectos
const tareas = allItems.filter(i => i.json.descripcion !== undefined).map(i => i.json);
const proyectos = allItems.filter(i => i.json.nombre !== undefined).map(i => i.json);
const proyecto = proyectos[0] || {};

const listaTareas = tareas.length > 0
  ? tareas.map((t, i) => `${i + 1}. ${t.descripcion}`).join('\n')
  : '(sin tareas pendientes)';

const contextoSupabase = `
---
ESTADO ACTUAL MSDS-CRM (en vivo desde Supabase — ${new Date().toISOString().slice(0, 10)}):
Checkpoint: ${proyecto.checkpoint || 'sin datos'}

TAREAS PENDIENTES:
${listaTareas}
---`;

const extractNode = $('Code — Extraer datos').first().json;

return [{ json: {
  chat_id: extractNode.chat_id,
  user_message: extractNode.user_message,
  contexto_supabase: contextoSupabase
} }];

const chatId = $('Code — Extraer datos').first().json.chat_id;
const text = $json.choices?.[0]?.message?.content || 'Sin respuesta de OpenAI';
if (!chatId) throw new Error('chat_id perdido');
return [{ json: { chat_id: chatId, response_text: text } }];
